package com.raonmate.backend.notification.api; import com.raonmate.backend.notification.application.NotificationService; import jakarta.validation.Valid; import java.util.*; import lombok.RequiredArgsConstructor; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/workshops/{workshopId}/notifications") @RequiredArgsConstructor public class NotificationController{private final NotificationService service;@GetMapping public List<NotificationResponse> list(@PathVariable UUID workshopId){return service.list(workshopId);}@PostMapping("/send")@ResponseStatus(HttpStatus.CREATED)public NotificationResponse send(@PathVariable UUID workshopId,@Valid @RequestBody NotificationSendRequest request){return service.send(workshopId,request);}}
